ALGORITHM AccessMatrixCheck
INPUT: domain, object, requested_operation
OUTPUT: Boolean (access granted or denied)

// Global Access Matrix Structure
// Rows = Domains, Columns = Objects
// Matrix[domain][object] = set of allowed operations

BEGIN
 // Step 1: Initialize the Access Matrix
 INITIALIZE Matrix as 2D array

 // Step 2: Define protection domains
 ADD domain "User_1" to Matrix
 ADD domain "User_2" to Matrix
 ADD domain "Kernel" to Matrix

 // Step 3: Define objects and their access rights
 SET Matrix["User_1"]["File_A"] = {read, write}
 SET Matrix["User_1"]["Printer"] = {}
 SET Matrix["User_2"]["File_A"] = {read}
 SET Matrix["User_2"]["Printer"] = {print}
 SET Matrix["Kernel"]["File_A"] = {read, write, delete}
 SET Matrix["Kernel"]["Printer"] = {print, manage}

 // Step 4: Access check function
 FUNCTION CheckAccess(domain, object, operation):
 IF operation is IN Matrix[domain][object]:
 RETURN TRUE // Access granted
 ELSE:
 RETURN FALSE // Access denied
 ENDIF
 END FUNCTION

 // Step 5: Example access verification
 result1 = CheckAccess("User_1", "File_A", "read")
 result2 = CheckAccess("User_2", "File_A", "write")

 // Step 6: Implement ACL-based approach (object-centric)
 FUNCTION GetACLForObject(object):
 acl_list = []
 FOR EACH domain IN Matrix:
 IF Matrix[domain][object] is not empty:
 ADD (domain, Matrix[domain][object]) TO acl_list
 ENDIF
 ENDFOR
 RETURN acl_list
 END FUNCTION

 // Step 7: Implement Capability List approach (domain-centric)
 FUNCTION GetCapabilitiesForDomain(domain):
 cap_list = []
 FOR EACH object IN Matrix[domain]:
 IF Matrix[domain][object] is not empty:
 ADD (object, Matrix[domain][object]) TO cap_list
 ENDIF
 ENDFOR
 RETURN cap_list
 END FUNCTION

 RETURN "Access Matrix Implementation Complete"
END

/*
 * Capability List Implementation in C
 * Demonstrates domain-centric (process-centric) protection mechanism
 * A capability is an unforgeable token that grants specific rights
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

#define MAX_CAPABILITIES 20
#define MAX_NAME_LENGTH 50

// Permission types
typedef enum {
 PERM_READ = 1,
 PERM_WRITE = 2,
 PERM_EXECUTE = 4,
 PERM_DELETE = 8,
 PERM_PRINT = 16
} Permission;

// Object in the system (file, device, etc.)
typedef struct {
 char name[MAX_NAME_LENGTH];
 int object_id;
} Object;

// Capability - unforgeable token granting access
typedef struct {
 Object* object; // Reference to the object
 Permission permissions; // Bitmask of granted permissions
 bool valid; // Is this capability valid?
 int capability_id; // Unique identifier (like file descriptor)
} Capability;

// Domain/Process with a Capability List
typedef struct {
 char domain_name[MAX_NAME_LENGTH];
 int domain_id;
 Capability* capabilities[MAX_CAPABILITIES];
 int cap_count;
} Domain;

// Global object table (simulating OS object table)
typedef struct {
 Object objects[10];
 int object_count;
} ObjectTable;

ObjectTable global_objects;

// Initialize the object table
void init_objects() {
 global_objects.object_count = 0;

 // Create some system objects
 strcpy(global_objects.objects[0].name, "secret.txt");
 global_objects.objects[0].object_id = 0;

 strcpy(global_objects.objects[1].name, "report.pdf");
 global_objects.objects[1].object_id = 1;

 strcpy(global_objects.objects[2].name, "printer");
 global_objects.objects[2].object_id = 2;

 global_objects.object_count = 3;
}

// Find object by name
Object* find_object(const char* name) {
 for (int i = 0; i < global_objects.object_count; i++) {
 if (strcmp(global_objects.objects[i].name, name) == 0) {
 return &global_objects.objects[i];
 }
 }
 return NULL;
}

// Create a new domain (process/user)
Domain* create_domain(const char* name) {
 Domain* domain = (Domain*)malloc(sizeof(Domain));
 strcpy(domain->domain_name, name);
 domain->domain_id = rand() % 1000;
 domain->cap_count = 0;

 printf("[Domain] Created domain: %s (ID: %d)\n", name, domain->domain_id);
 return domain;
}

// Grant a capability to a domain (like open() system call)
Capability* grant_capability(Domain* domain, Object* obj, Permission perms) {
 if (domain->cap_count >= MAX_CAPABILITIES) {
 printf("[Error] Capability list full for domain %s\n", domain->domain_name);
 return NULL;
 }

 Capability* cap = (Capability*)malloc(sizeof(Capability));
 cap->object = obj;
 cap->permissions = perms;
 cap->valid = true;
 cap->capability_id = rand() % 10000;

 domain->capabilities[domain->cap_count++] = cap;

 printf("[Capability] Granted to %s: %s with permissions: ", 
 domain->domain_name, obj->name);
 if (perms & PERM_READ) printf("READ ");
 if (perms & PERM_WRITE) printf("WRITE ");
 if (perms & PERM_EXECUTE) printf("EXEC ");
 if (perms & PERM_DELETE) printf("DELETE ");
 printf("\n");

 return cap;
}

// Check if domain has specific permission on an object
bool check_access(Domain* domain, const char* object_name, Permission required_perm) {
 // Find the object
 Object* obj = find_object(object_name);
 if (obj == NULL) {
 printf("[Access DENIED] Object '%s' not found\n", object_name);
 return false;
 }

 // Search through capability list
 for (int i = 0; i < domain->cap_count; i++) {
 Capability* cap = domain->capabilities[i];
 if (cap->valid && cap->object->object_id == obj->object_id) {
 // Check if permission is granted
 if (cap->permissions & required_perm) {
 printf("[Access GRANTED] %s -> %s (%s)\n", 
 domain->domain_name, object_name, 
 (required_perm == PERM_READ) ? "READ" :
 (required_perm == PERM_WRITE) ? "WRITE" :
 (required_perm == PERM_DELETE) ? "DELETE" : "OTHER");
 return true;
 } else {
 printf("[Access DENIED] %s lacks permission for %s\n",
 domain->domain_name, object_name);
 return false;
 }
 }
 }

 printf("[Access DENIED] %s has no capability for %s\n",
 domain->domain_name, object_name);
 return false;
}

// Revoke capability (like close() system call)
void revoke_capability(Domain* domain, const char* object_name) {
 for (int i = 0; i < domain->cap_count; i++) {
 if (strcmp(domain->capabilities[i]->object->name, object_name) == 0) {
 domain->capabilities[i]->valid = false;
 printf("[Capability] Revoked: %s from %s\n",
 object_name, domain->domain_name);
 return;
 }
 }
}

// Display capability list for a domain
void display_capabilities(Domain* domain) {
 printf("\n=== Capability List for %s ===\n", domain->domain_name);
 for (int i = 0; i < domain->cap_count; i++) {
 Capability* cap = domain->capabilities[i];
 if (cap->valid) {
 printf(" [%d] %s - ", cap->capability_id, cap->object->name);
 if (cap->permissions & PERM_READ) printf("R ");
 if (cap->permissions & PERM_WRITE) printf("W ");
 if (cap->permissions & PERM_EXECUTE) printf("X ");
 if (cap->permissions & PERM_DELETE) printf("D ");
 printf("\n");
 }
 }
 printf("================================\n\n");
}

int main() {
 printf("=== Capability-Based Protection System ===\n\n");

 // Initialize system objects
 init_objects();

 // Create domains (simulating processes/users)
 Domain* user_process = create_domain("UserProcess_1");
 Domain* admin_process = create_domain("AdminProcess");

 printf("\n--- Granting Capabilities (Principle of Least Privilege) ---\n");

 // Grant capabilities - Principle of Least Privilege
 // User process gets minimal permissions
 Object* file1 = find_object("secret.txt");
 Object* file2 = find_object("report.pdf");
 Object* printer = find_object("printer");

 grant_capability(user_process, file1, PERM_READ); // Only read access
 grant_capability(user_process, file2, PERM_READ | PERM_WRITE); // Read and write
 grant_capability(user_process, printer, PERM_PRINT); // Print only

 // Admin gets more privileges
 grant_capability(admin_process, file1, PERM_READ | PERM_WRITE | PERM_DELETE);
 grant_capability(admin_process, file2, PERM_READ | PERM_WRITE | PERM_DELETE);
 grant_capability(admin_process, printer, PERM_READ | PERM_WRITE | PERM_DELETE);

 // Display capabilities
 display_capabilities(user_process);
 display_capabilities(admin_process);

 printf("--- Testing Access Requests ---\n");

 // Test access attempts
 check_access(user_process, "secret.txt", PERM_READ);
 check_access(user_process, "secret.txt", PERM_WRITE);
 check_access(user_process, "report.pdf", PERM_WRITE);
 check_access(admin_process, "secret.txt", PERM_DELETE);

 printf("\n--- Demonstrating Capability Revocation ---\n");
 revoke_capability(user_process, "report.pdf");
 check_access(user_process, "report.pdf", PERM_READ);

 return 0;
}
